const targetMap = { 0: 1, 2: 3, 6: 7, 13: 14, 20: 21 };

function getTaipeiDateOnly() {
  const now = new Date();
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'Asia/Taipei',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).format(now).split('-').map(Number);
  return new Date(Date.UTC(parts[0], parts[1] - 1, parts[2]));
}

function parseDateOnly(dateStr) {
  if (!dateStr) return null;
  const clean = String(dateStr).trim().slice(0, 10);
  const parts = clean.split('-').map(Number);
  if (parts.length !== 3 || parts.some(Number.isNaN)) return null;
  return new Date(Date.UTC(parts[0], parts[1] - 1, parts[2]));
}

function taipeiNowString() {
  return new Intl.DateTimeFormat('sv-SE', {
    timeZone: 'Asia/Taipei',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit'
  }).format(new Date()).replace(' ', ' ');
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function renderEmail(title, eyebrow, headline, name, bodyHtml, footerNote = '此信件為身心平衡關懷內容，請依您的需求與節奏進行選擇。') {
  const safeTitle = escapeHtml(title);
  const safeEyebrow = escapeHtml(eyebrow);
  const safeHeadline = headline;
  const safeName = escapeHtml(name || '您好');
  const safeFooter = escapeHtml(footerNote);

  return `<!DOCTYPE html>
<html lang="zh-Hant">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${safeTitle}</title>
</head>
<body style="margin:0; padding:0; background-color:#f4f6f8; font-family:Arial, 'Noto Sans TC', 'PingFang TC', 'Microsoft JhengHei', sans-serif; color:#333333;">
  <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color:#f4f6f8; margin:0; padding:0;">
    <tr>
      <td align="center" style="padding:32px 16px;">
        <table role="presentation" width="100%" cellpadding="0" cellspacing="0" border="0" style="max-width:640px; background-color:#ffffff; border-radius:16px; overflow:hidden; box-shadow:0 4px 18px rgba(0,0,0,0.06);">
          <tr>
            <td style="background:linear-gradient(135deg, #1f3c88 0%, #4b6cb7 100%); padding:32px 36px; text-align:left;">
              <div style="font-size:14px; line-height:1.6; color:#dfe8ff; letter-spacing:1px;">${safeEyebrow}</div>
              <div style="font-size:28px; line-height:1.4; font-weight:bold; color:#ffffff; margin-top:8px;">${safeHeadline}</div>
            </td>
          </tr>
          <tr>
            <td style="padding:36px;">
              <p style="margin:0 0 20px; font-size:16px; line-height:1.9; color:#333333;">${safeName} 您好，</p>
              ${bodyHtml}
            </td>
          </tr>
          <tr>
            <td style="padding:20px 36px 28px; background-color:#fafbfc; border-top:1px solid #edf0f2;">
              <p style="margin:0; font-size:12px; line-height:1.8; color:#999999; text-align:center;">${safeFooter}</p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;
}

function buildCtaBlock() {
  return `
    <table role="presentation" cellpadding="0" cellspacing="0" border="0" align="center" style="margin:8px auto 28px;">
      <tr>
        <td align="center" bgcolor="#1f3c88" style="border-radius:999px;">
          <a href="https://timewaver-audio-sales.netlify.app/" target="_blank" style="display:inline-block; padding:16px 32px; font-size:16px; font-weight:bold; color:#ffffff; text-decoration:none; border-radius:999px;">
            立即進入專屬調整入口
          </a>
        </td>
      </tr>
    </table>`;
}

function buildCallout(title, body) {
  return `
    <div style="margin:0 0 28px; padding:20px 22px; background-color:#f7f9fc; border-left:4px solid #4b6cb7; border-radius:10px;">
      <div style="font-size:18px; line-height:1.8; font-weight:bold; color:#1f3c88;">${title}</div>
      <div style="margin-top:8px; font-size:16px; line-height:1.9; color:#333333;">${body}</div>
    </div>`;
}

function buildWarmBox(title, body) {
  return `
    <div style="margin:28px 0; padding:22px; background-color:#fffaf0; border:1px solid #f2dfb0; border-radius:12px;">
      <div style="font-size:18px; line-height:1.8; font-weight:bold; color:#8a5a00; margin-bottom:8px;">${title}</div>
      <div style="font-size:16px; line-height:1.9; color:#5c4a1f;">${body}</div>
    </div>`;
}

function buildObservationBlock(observation) {
  return `
    <div style="margin:0 0 28px; padding:20px 22px; background-color:#f7f9fc; border-left:4px solid #4b6cb7; border-radius:10px;">
      <div style="font-size:18px; line-height:1.8; font-weight:bold; color:#1f3c88;">💡 今晚 / 今日的觀察指標</div>
      <div style="margin-top:8px; font-size:16px; line-height:1.9; color:#333333;">${observation}</div>
    </div>`;
}

function buildDay1(name, p) {
  const body = `
    ${buildCallout('⚖️ 專屬頻率已完成載入', `您的專屬方案是 <span style="font-weight:bold; color:#1f3c88;">${escapeHtml(p.prescription_name)}</span>。${escapeHtml(p.focus_body)}`)}
    <p style="margin:0 0 18px; font-size:16px; line-height:1.9; color:#333333;">歡迎啟動這趟為期 21 天的神經重置旅程。這不是一般的背景音，而是一段幫助您慢慢校準節奏、回到比較穩定狀態的入口。</p>
    ${buildObservationBlock(p.observation_indicators)}
    <p style="margin:0 0 18px; font-size:16px; line-height:1.9; color:#333333;">前幾天您可能會感受到特別放鬆，或反而出現多夢、思緒翻騰的現象，這都是潛意識正在釋放深層壓力的正常排毒反應。</p>
    ${buildWarmBox('有些改變，不是從知道更多開始', '而是從您願意在對的時候，為自己做一次真正的調整開始。')}
    <p style="margin:0 0 28px; font-size:16px; line-height:1.9; color:#333333;">請保持每天聆聽的節奏，讓身心系統有機會在穩定重複中重新找到回穩的方式。</p>
    ${buildCtaBlock()}
    <p style="margin:0; font-size:15px; line-height:1.9; color:#666666; text-align:center;">願您重新找回安定、放鬆與內在的平衡。我們 Day 3 見。</p>`;
  return renderEmail('Day 1 啟動', '21 天神經重置旅程', '您的專屬調整，現在開始', name, body);
}

function buildStandardDay(name, title, subtitle, headline, intro, observation, closing) {
  const body = `
    <p style="margin:0 0 18px; font-size:16px; line-height:1.9; color:#333333;">${intro}</p>
    ${buildObservationBlock(observation)}
    ${buildWarmBox('真正的改變，不會每一天都很戲劇化', '很多時候，系統真正穩下來的樣子，不是更強烈，而是更自然。')}
    ${buildCtaBlock()}
    <p style="margin:0; font-size:15px; line-height:1.9; color:#666666; text-align:center;">${closing}</p>`;
  return renderEmail(title, subtitle, headline, name, body);
}

