  return renderEmail('Day 21：完成基礎重置', '神經重置達標', '下一步，讓穩定真正留住', name, body);
}

const today = getTaipeiDateOnly();
const out = [];

for (const item of items) {
  const row = item.json;
  const startDate = parseDateOnly(row.start_date);
  if (!startDate) continue;

  const diffDays = Math.floor((today - startDate) / 86400000);
  const targetDay = targetMap[diffDays] || null;
  const lastSentDay = Number(row.last_sent_day || 0);
  const status = String(row.status || '').trim();
  const productCode = String(row.product_code || '').toUpperCase();
  const buyerEmail = String(row.buyer_email || '').trim();

  if (!targetDay) continue;
  if (!buyerEmail) continue;
  if (status === 'completed') continue;
  if (lastSentDay >= targetDay) continue;
  if (!PRODUCT_DATA[productCode]) continue;

  const p = PRODUCT_DATA[productCode];
  const buyerName = row.buyer_name || '';
  let subject = '';
  let html = '';

  if (targetDay === 1) {
    subject = `【專屬載入】您的 ${p.prescription_name} 已生成 (Day 1)`;
    html = buildDay1(buyerName, p);
  } else if (targetDay === 3) {
    subject = '【頻率適應期】Day 3 觀察：您的大腦正在重新連線';
    html = buildStandardDay(
      buyerName,
      'Day 3：系統開始整理',
      '有反應，代表系統已經啟動',
      '您的大腦正在重新連線',
      p.day3_content,
      p.observation_indicators,
      '請繼續保持節奏，讓系統慢慢回到更穩定的位置。我們 Day 7 見。'
    );
  } else if (targetDay === 7) {
    subject = '【頻率校準週報】Day 7 深空適應期狀態確認';
    html = buildStandardDay(
      buyerName,
      'Day 7：第一週完成',
      '改變，正在從底層發生',
      '恭喜您完成了第一週的基礎校準',
      `${p.day7_content} 這幾天，您可能會發現一個現象：第一天聆聽時那種「強烈的放鬆感或衝擊感」似乎變平淡了。千萬別誤以為是音頻失效！在神經科學與頻率應用中，這稱為「同化效應（Assimilation Effect）」。這是一個極佳的訊號，代表您的大腦已經習慣了這個高質量的波長，並將它視為新的「底線狀態」。您的抗壓閾值與基礎能量，正在不知不覺中往上升級。`,
      p.observation_indicators,
      '享受這個逐漸成為常態的平靜，我們下週繼續觀察。'
    );
  } else if (targetDay === 14) {
    subject = '【深層清理期】Day 14：那些浮現的夢境與情緒';
    html = buildStandardDay(
      buyerName,
      'Day 14：穩定感開始成形',
      '第二週的關鍵，是讓系統真正鬆開',
      '兩週過去了，您的頻率地基已經初步打穩',
      `${p.day14_content} 現在，這組頻率已經成為您強大的防護罩。然而，如同重訓一樣，如果每天都舉同樣的重量，肌肉就不會再增長；大腦的神經迴路也是如此，長時間接收單一頻率，最終會產生「頻率疲勞」，導致成長停滯。要讓大腦持續擴充心智頻寬、避免舊有慣性與焦慮感反撲，我們需要的是「節奏性的頻率切換」與更深層的底層邏輯重置。`,
      p.observation_indicators,
      '請繼續陪自己的系統走完這段路，最後一週不是收尾，而是讓重置真正完成。我們 Day 21 見。'
    );
  } else {
    subject = '【維度躍遷完成】Day 21：您的神經重置已達標';
    html = buildDay21(buyerName, p);
  }

  out.push({
    json: {
      ...row,
      target_day: targetDay,
      email_subject: subject,
      email_html: html,
      status: targetDay === 21 ? 'completed' : `Day ${targetDay} - Sent`,
      last_sent_day: String(targetDay),
      last_sent_at: taipeiNowString()
    }
  });
}

return out;
